using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllReflectedInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 2, 5.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 3, 10.00m);

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", 0, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", -1, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", 1, -5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void AddItem_NullSku_ThrowsArgumentNullException()
    {
        _cart.AddItem(null!, 1, 10.00m);
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", 2, 15.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        _cart.RemoveItem("SKU-999");
    }

    [TestMethod]
    public void RemoveItem_OneOfMultipleItems_OnlyRemovesTargeted()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void RemoveItem_NullSku_ThrowsArgumentNullException()
    {
        _cart.RemoveItem(null!);
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 3, 7.50m);

        Assert.AreEqual(22.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon("BOGUS");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_EmptyCart_ThrowsInvalidOperationException()
    {
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    public void ApplyCoupon_TotalDoesNotGoBelowZero()
    {
        _cart.AddItem("SKU-001", 1, 1.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() >= 0.00m);
    }
}

